account.deposit(50)
print(account.get_balance())

class BankAccount:
    def __init__(self, owner, balance=0):
        self.owner = owner
        self.__balance = balance

    def deposit(self, amount):
        if amount <= 0:
            raise ValueError("Deposit must be positive")
        self.__balance += amount

    def withdraw(self, amount):
        if amount > self.__balance:
            raise ValueError("Not enough funds")
        self.__balance -= amount

    def get_balance(self):
        return self.__balance

acc = BankAccount("Alice", 200)
acc.deposit(50)
acc.withdraw(30)
print(acc.get_balance())

class Temperature:
    def __init__(self, celsius):
        self.__celsius = celsius

    @property
    def celsius(self):
        return self.__celsius

    @celsius.setter
    def celsius(self, value):
        if value < -273.15:
            raise ValueError("Temperature below absolute zero!")
        self.__celsius = value

    @property
    def fahrenheit(self):
        return self.__celsius * 9 / 5 + 32

t = Temperature(25)
print(t.celsius)      # calls the getter
print(t.fahrenheit)   # computed on the fly
t.celsius = 100       # calls the setter
print(t.fahrenheit)

class User:
    def __init__(self, username, age):
        self.username = username   # public
        self._role = "member"      # protected convention
        self.__age = age           # private, validated via property

    @property
    def age(self):
        return self.__age

    @age.setter
    def age(self, value):
        if not isinstance(value, int) or value < 0:
            raise ValueError("Age must be a non-negative integer")
        self.__age = value

    def profile(self):
        return f"{self.username} ({self.__age}) — {self._role}"

u = User("alice99", 28)
print(u.profile())
u.age = 29
print(u.age)

